export type TreeNode = {
  name: string;
  path: string;
  type: "file" | "dir";
  children?: TreeNode[] | null;
};

export type AskUsage = {
  input_tokens: number;
  output_tokens: number;
  cache_read_input_tokens: number;
  cache_creation_input_tokens: number;
  sections: Record<string, number>;
};

export type AskStep = {
  label: string;
  detail?: string;
  paths?: string[];
};

export type AskResponse = {
  path?: string;
  answer?: string;
  usage?: AskUsage;
  steps?: AskStep[];
};

const base = "/api/v1";

export async function fetchProperties(): Promise<string[]> {
  const r = await fetch(`${base}/wiki/properties`);
  if (!r.ok) throw new Error(`properties ${r.status}`);
  return r.json();
}

export async function fetchTree(lie: string): Promise<TreeNode> {
  const r = await fetch(`${base}/wiki/tree?lie=${encodeURIComponent(lie)}`);
  if (!r.ok) throw new Error(`tree ${r.status}`);
  return r.json();
}

export async function fetchFile(path: string): Promise<string> {
  const r = await fetch(`${base}/wiki/file?path=${encodeURIComponent(path)}`);
  if (!r.ok) throw new Error(`file ${r.status}`);
  return r.text();
}

export type AskTurn = { question: string; answer: string };

export async function ask(
  question: string,
  lie: string,
  history: AskTurn[] = [],
): Promise<{ ok: true; data: AskResponse } | { ok: false; status: number }> {
  const r = await fetch(`${base}/ask`, {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify({ question, lie, history }),
  });
  if (!r.ok) return { ok: false, status: r.status };
  return { ok: true, data: await r.json() };
}

export async function askStream(
  question: string,
  lie: string,
  history: AskTurn[],
  handlers: {
    onStep: (step: AskStep) => void;
    onResponse: (resp: AskResponse) => void;
    onError: (err: { status: number; detail: string }) => void;
  },
  signal?: AbortSignal,
): Promise<void> {
  const r = await fetch(`${base}/ask/stream`, {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify({ question, lie, history }),
    signal,
  });
  if (!r.ok || !r.body) {
    handlers.onError({
      status: r.status,
      detail: await r.text().catch(() => ""),
    });
    return;
  }
  const reader = r.body.getReader();
  const decoder = new TextDecoder();
  let buf = "";
  while (true) {
    const { value, done } = await reader.read();
    if (done) break;
    buf += decoder.decode(value, { stream: true });
    let idx;
    while ((idx = buf.indexOf("\n\n")) !== -1) {
      const block = buf.slice(0, idx);
      buf = buf.slice(idx + 2);
      const dataLine = block.split("\n").find((l) => l.startsWith("data:"));
      if (!dataLine) continue;
      const json = dataLine.slice(5).trim();
      try {
        const parsed = JSON.parse(json) as {
          stage: string;
          data: Record<string, unknown>;
        };
        if (parsed.stage === "step") {
          handlers.onStep(parsed.data as unknown as AskStep);
        } else if (parsed.stage === "response") {
          handlers.onResponse(parsed.data as unknown as AskResponse);
        } else if (parsed.stage === "error") {
          handlers.onError(
            parsed.data as unknown as { status: number; detail: string },
          );
        }
      } catch {
        // ignore malformed
      }
    }
  }
}

export type SimItem = {
  id: string;
  kind: "email" | "invoice" | "bank";
  label: string;
  detail: string;
  source_path: string | null;
  month: string | null;
};

export type SimDay = {
  day: number;
  content_date: string | null;
  emails: SimItem[];
  invoices: SimItem[];
  bank: SimItem[];
};

export type SimTouched = { path: string; content: string; previous: string };

export type SimIngestResponse = {
  status: string;
  workspace: string;
  wiki_dir: string;
  provider: string;
  fast_model: string;
  smart_model: string;
  duration_ms: number;
  classification: {
    signal: boolean;
    category: string;
    priority: string;
    confidence: number;
  } | null;
  applied_ops: number;
  commit_sha: string | null;
  idempotent: boolean;
  touched: string[];
  files: SimTouched[];
  normalized_text: string | null;
  git_log: string[];
};

export async function fetchIncremental(): Promise<SimDay[]> {
  const r = await fetch(`${base}/sim/incremental`);
  if (!r.ok) throw new Error(`incremental ${r.status}`);
  return r.json();
}

export async function runSimIngest(body: {
  day: number;
  kind: "email" | "invoice" | "bank";
  id: string;
  mode: "isolated" | "live";
  property_id?: string;
}): Promise<SimIngestResponse> {
  const r = await fetch(`${base}/sim/ingest`, {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify(body),
  });
  if (!r.ok) {
    const detail = await r.text();
    throw new Error(`sim/ingest ${r.status}: ${detail}`);
  }
  return r.json();
}

export type SimStageEvent = {
  stage: string;
  data: Record<string, unknown>;
};

export async function runSimIngestStream(
  body: {
    day: number;
    kind: "email" | "invoice" | "bank";
    id: string;
    mode: "isolated" | "live";
    property_id?: string;
  },
  handlers: {
    onStage: (ev: SimStageEvent) => void;
    onResponse: (resp: SimIngestResponse) => void;
    onError: (err: { status: number; detail: string }) => void;
  },
  signal?: AbortSignal,
): Promise<void> {
  const r = await fetch(`${base}/sim/ingest/stream`, {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify(body),
    signal,
  });
  if (!r.ok || !r.body) {
    const detail = await r.text().catch(() => "");
    throw new Error(`sim/ingest/stream ${r.status}: ${detail}`);
  }
  const reader = r.body.getReader();
  const decoder = new TextDecoder();
  let buf = "";
  while (true) {
    const { value, done } = await reader.read();
    if (done) break;
    buf += decoder.decode(value, { stream: true });
    let idx;
    while ((idx = buf.indexOf("\n\n")) !== -1) {
      const block = buf.slice(0, idx);
      buf = buf.slice(idx + 2);
      const dataLine = block
        .split("\n")
        .find((l) => l.startsWith("data:"));
      if (!dataLine) continue;
      const json = dataLine.slice(5).trim();
      try {
        const parsed = JSON.parse(json) as
          | { stage: string; data: Record<string, unknown> }
          | Record<string, unknown>;
        const stage = (parsed as { stage?: string }).stage;
        if (stage === "response") {
          handlers.onResponse(
            (parsed as { data: SimIngestResponse }).data,
          );
        } else if (stage === "error") {
          handlers.onError(
            (parsed as { data: { status: number; detail: string } }).data,
          );
        } else if (typeof stage === "string") {
          handlers.onStage(parsed as SimStageEvent);
        }
      } catch {
        // ignore malformed
      }
    }
  }
}

export type HumanNotes = { path: string; body: string };

export async function fetchHumanNotes(path: string): Promise<HumanNotes> {
  const r = await fetch(
    `${base}/wiki/human-notes?path=${encodeURIComponent(path)}`,
  );
  if (!r.ok) throw new Error(`human-notes ${r.status}`);
  return r.json();
}

export async function saveHumanNotes(
  path: string,
  body: string,
  pmUser: string,
): Promise<{ path: string; bytes_written: number; commit_sha: string | null }> {
  const r = await fetch(
    `${base}/wiki/human-notes?path=${encodeURIComponent(path)}`,
    {
      method: "PUT",
      headers: {
        "content-type": "application/json",
        "x-pm-user": pmUser,
      },
      body: JSON.stringify({ body }),
    },
  );
  if (!r.ok) {
    const detail = await r.text();
    throw new Error(`human-notes save ${r.status}: ${detail}`);
  }
  return r.json();
}

